def solve(weight_kg):
    # Step 1: Determine the weight category of the child
    if weight_kg <= 10:
        category = "≤10 kg"
    elif 11 <= weight_kg <= 20:
        category = "11-20 kg"
    else:
        category = ">20 kg"

    yield {
        "step_name": "determine_weight_category",
        "step_description": "Determine the weight category of the child to apply the correct formula for calculating daily maintenance fluid requirement.",
        "step_result": category,
        "unit": None
    }

    # Step 2: Calculate the maintenance fluid requirement based on the weight category
    if category == "≤10 kg":
        fluid_requirement_ml = weight_kg * 100
    elif category == "11-20 kg":
        fluid_requirement_ml = 1000 + (weight_kg - 10) * 50
    else:  # category == ">20 kg"
        fluid_requirement_ml = 1500 + (weight_kg - 20) * 20

    # Ensure the result does not exceed 2400 mL
    if fluid_requirement_ml > 2400:
        fluid_requirement_ml = 2400

    yield {
        "step_name": "calculate_maintenance_fluid_requirement",
        "step_description": "Calculate the daily maintenance fluid requirement using the Holliday-Segar formula based on the child's weight category.",
        "step_result": fluid_requirement_ml,
        "unit": "mL"
    }

    return fluid_requirement_ml
